// // This ROM module outputs a single-bit signal based on a 7-bit address input. When the clock signal transitions to a negative edge, the module checks the address; if the address is either 97 or 98, it sets the output (q) to low (0), otherwise, it sets the output to high (1).
module top_module(
		input	[6:0]	address,
		input		clock,
		output  reg q 

);always@(posedge clock)
begin
	case(address)
7'd97 :   q=1;
7'd98 :   q=1;
default :   q=0;		

	endcase
end




endmodule
